SELECT TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN MAX(TDS.SHIP_NAME) || '_' || MAX(TDSI.VOYAGE) END "shipNameVoyage", MAX(TDS.SCN) "scn", REGEXP_REPLACE(LISTAGG(TBT.ID, ',') WITHIN GROUP (ORDER BY TBT.ID), '([^,]+)(,\1)+', '\1') "trustIds", REGEXP_REPLACE(LISTAGG(TO_CHAR(TBT.TRUST_NO), ',') WITHIN GROUP (ORDER BY TBT.TRUST_NO), '([^,]+)(,\1)+', '\1') "trustNos", TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, MC.WORK_TYPE, DECODE(MC.WORK_TYPE, '1', '件杂', '2', '散杂', '3', '木材', NULL) "workTypeLabel", TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, MAX(TDS.BERTH_TIME) "berthTime", MAX(TDS.LEAVE_BERTH_TIME) "leaveBerthTime", MAX(TDS.LEAVE_PORT_TIME), REGEXP_REPLACE(LISTAGG(TO_CHAR(TBT.RELEASE_TIME, 'yyyy-MM-dd HH:mm:ss'), ',') WITHIN GROUP (ORDER BY TBT.RELEASE_TIME), '([^,]+)(,\1)+', '\1') "releaseTimes", MAX(TDSI.LOAD_UNLOAD) "loadUnload", MAX(TDSI.IMP_EXP) "impExp", MAX(DECODE(TDSI.IMP_EXP, 'IN', '进口', '出口')) "impExpLabel", MAX(TDSI.WORK_END_TIME) "workEndTime", CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - MAX(TDS.BERTH_TIME) ELSE NVL2(TBCI.CLEAR_DATE, GREATEST(MAX(TDSI.WORK_END_TIME), TEMP3.MAX_WEIGH_OUT_DT), SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END - CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END "overdueDays", TBCI.IS_CLEAR, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE FROM T_BUS_CARGO_INFO TBCI LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP5 ON TBCI.ID = TEMP5.CARGO_INFO_ID JOIN M_CARGO MC ON TBCI.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBCI.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBCI.ID = TBTC.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID LEFT JOIN (SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST WHERE CHARGE_STATUS != '30' UNION SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST_TRANSFER WHERE CHARGE_STATUS != '30') TBH ON TBCI.ID = TBH.CARGO_INFO_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) MIN_WEIGH_OUT_DT, MAX(TEMP.WEIGH_OUT_DT) MAX_WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '疏港') TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '疏港') TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) MIN_WEIGH_OUT_DT, MAX(TEMP.WEIGH_OUT_DT) MAX_WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP2 ON TBCI.ID = TEMP2.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) MIN_WEIGH_OUT_DT, MAX(TEMP.WEIGH_OUT_DT) MAX_WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '陆销') TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '陆销') TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP3 ON TBCI.ID = TEMP3.CARGO_INFO_ID LEFT JOIN (SELECT TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, MIN(TBCR.FREE_STORAGE_DAYS) FREE_STORAGE_DAYS FROM T_BUS_CONTRACT_COMPANY TBCC JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBCR.RATE_ITEM_CODE = 'MS00240' AND TBC.ID = TBCR.CONTRACT_ID) GROUP BY TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE) TEMP4 ON (TBCI.COMPANY_ID = TEMP4.COMPANY_ID AND TBCI.CARGO_OWNER_ID = TEMP4.CUSTOMER_ID AND CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END >= TEMP4.START_TIME AND CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END <= TEMP4.END_TIME AND TBCI.CARGO_CODE = TEMP4.CARGO_CODE)
AND TBCI.SOURCE = '50'
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike,jdbcType=VARCHAR}
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}
AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=BIGINT}
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE NVL2(TBCI.CLEAR_DATE, GREATEST(TDSI.WORK_END_TIME, TEMP3.MAX_WEIGH_OUT_DT), SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END - CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END > 0
AND CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE NVL2(TBCI.CLEAR_DATE, GREATEST(TDSI.WORK_END_TIME, TEMP3.MAX_WEIGH_OUT_DT), SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END - CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END <= 0
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
AND TBCI.CARGO_CODE LIKE #{cargoCodeLike,jdbcType=VARCHAR}
AND TDSI2.IMP_EXP = #{impExp,jdbcType=VARCHAR}
GROUP BY TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.ID, MC.WORK_TYPE, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.CREATE_TIME, TEMP.MIN_WEIGH_OUT_DT, TEMP.MAX_WEIGH_OUT_DT, TEMP2.MIN_WEIGH_OUT_DT, TEMP2.MAX_WEIGH_OUT_DT, TEMP3.MIN_WEIGH_OUT_DT, TEMP3.MAX_WEIGH_OUT_DT, TBCI.ROOT_ID, TBCI.RESIDUE_STORAGE, TEMP4.FREE_STORAGE_DAYS, TBCI.IS_CLEAR, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_TIME ORDER BY CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - MAX(TDS.BERTH_TIME) ELSE NVL2(TBCI.CLEAR_DATE, GREATEST(MAX(TDSI.WORK_END_TIME), TEMP3.MAX_WEIGH_OUT_DT), SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END - CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END DESC NULLS LAST

SELECT TCSSD.ID, TCSSD.STORAGE_SETTLE_ID, TCSSD."DATE", TCSSD.TON, TCSSD.BILLABLE_TON, TCSSD.IN_TON, TCSSD.OUT_TON, TCSSD.AMOUNT, TCSSD.TAX_AMOUNT FROM T_COST_STORAGE_SETTLE_DETAIL TCSSD JOIN T_COST_STORAGE_SETTLE TCSS ON TCSSD.STORAGE_SETTLE_ID = TCSS.ID WHERE TCSS.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
AND TCSSD."DATE" >= #{startDate,jdbcType=TIMESTAMP}
AND TCSSD."DATE" <= #{endDate,jdbcType=TIMESTAMP}

mapper.update:
UPDATE T_COST_STORAGE_SETTLE
SET STATUS         = #{status,jdbcType=VARCHAR},
    REVIEW_BY      = #{loginUserId,jdbcType=BIGINT},
    REVIEW_BY_NAME = #{loginUserName,jdbcType=BIGINT},
    REVIEW_BY_TIME = #{now,jdbcType=BIGINT}
WHERE ID = #{id,jdbcType=BIGINT}
